var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이런, 어떻게든 포드를 요격했어야 했는데……!","JPN":"まずい、ポッドを先に迎撃するべきでした……！","ENG":"Drat, we should have intercepted the pod!","TWN":"可惡！剛剛應該要攔截住逃生艙的……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"아직 일어설 수 있군. 카운터는 역시 튼튼해서 좋아.","JPN":"まだ立ちあがるのか。やはりカウンターは頑丈でいい。","ENG":"You can still stand. You Counters are so strong.","TWN":"還站得起來呢！我就喜歡制裁者這麼有韌性！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_A","text":{"KOREA":"실장님한테서 떨어져라! 이 괴물 자식!","JPN":"室長から離れろ！　この化け物め！","ENG":"Get away from the Chief, you monster!","TWN":"你這怪物！給我離室長遠一點！！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"초, 총이 어째서 안 나가는 거지? 탄약은 아직……","JPN":"じゅ、銃が発射できない？　弾切れでもないのに……","ENG":"W-why can't I fire my gun? I still have enough ammo.","TWN":"槍…槍怎麼無法發射？子彈還在……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그 여자가 부리는 기생충이 어떻게 돼 먹은 물건인진 몰라도 효과 하난 확실하군.","JPN":"あの女が操る寄生虫がどういう仕組みか知らないが、効き目は抜群だな。","ENG":"I don't know what kind of parasites she's using, but they work like a charm.","TWN":"那女人操控的寄生蟲效果真的很不錯呢！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그러게 쓸데없이 복잡한 무기만 좋아하면 안 되지.","JPN":"無駄に複雑な武器ばかり好むからそんな目にあうんだ。","ENG":"This is why you shouldn't rely on complex weapons like that.","TWN":"我說，怎麼可以只喜歡用那種複雜又沒用的武器呢！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"총까지 먹통으로 만들다니…… 무슨 짓을 한 거지?","JPN":"銃まで使えなくする……どういうことだ？","ENG":"You've made our guns useless. What did you do?","TWN":"竟然把槍變成廢鐵……你做了什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"글쎄? 지금 그게 중요한가?","JPN":"さあな。今そんなことが大事か？","ENG":"Well, is that really important right now?","TWN":"妳說呢？現在這是重點嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"먼저 안 오면 이쪽에서 간다.","JPN":"かかってこないなら、こちらから行くぞ。","ENG":"If you won't come, I'll come to you.","TWN":"妳不過來的話我就過去囉！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"큭……?!","JPN":"くっ……！","ENG":"Ugh!","TWN":"咳……？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"이건…… 전자기 펄스?","JPN":"これは……電磁パルス？","ENG":"This is... an EMP?","TWN":"這是…… 電磁脈衝？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"함내 방송을 듣고 바로 달려왔어요. 다들 괜찮으세요?","JPN":"艦内放送を聞いて参りました。皆さん大丈夫ですか？","ENG":"I came as soon as I heard the alert. Are you okay?","TWN":"我聽到艦隊的廣播後就立刻趕過來了，大家都沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨!","JPN":"お嬢様！","ENG":"Miss Jia!","TWN":"小姐！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"조심하세요! 저 자와 가까이 있으면 장비를 사용할 수 없습니다!","JPN":"気をつけてください！　あの者の近くにいると装備を使用できません！","ENG":"Watch out! Stay away from him, or you can't use your gear!","TWN":"小心！和那傢伙靠太近的話，裝備會無法使用！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"……오.","JPN":"……おお。","ENG":"Oh.","TWN":"……哦！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그 때 그 배짱 좋은 카운터로군.","JPN":"あの時の度胸がいいカウンターか。","ENG":"You're that spunky Counter from the last time.","TWN":"妳不是那時候很有膽識的制裁者嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"자, 도망치지 말고 나랑 한 판 붙어 보지.","JPN":"さあ、逃げるなよ。勝負しようぜ。","ENG":"Come on, don't run. Let's have a fight.","TWN":"別想逃喔！和我打一場吧！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 좋아요. 한 번 겨뤄 보죠.","JPN":"ええ、いいですよ。手合わせしましょう。","ENG":"Sure, let's do that.","TWN":"好的，我們就打一場吧！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"음? 패기가 마음에 드는걸?","JPN":"ほう？　その覇気は気に入ったぞ。","ENG":"Mm? I like your spirit.","TWN":"哦？我喜歡妳的霸氣！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 그 전에 쓰지도 못할 총은 버리고 제대로 된 무길 드는 편이……","JPN":"だが、その前に使えない銃は捨てて、まともな武器を持った方が……","ENG":"But I suggest you throw away that useless gun and pick up...","TWN":"不過在這之前，妳還是扔掉沒用的槍，拿起真正的武器……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"좋을 텐데!","JPN":"いいぜ！","ENG":"a more decent weapon!","TWN":"再來跟我打吧！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"음?","JPN":"む？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"내 공격을…… 총 한 자루로 쳐낸다고?","JPN":"俺の攻撃を……銃一丁で返しただと？","ENG":"You deflected my attack with a single gun?","TWN":"區區一把槍……就擋掉我的攻擊？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 네. 그러면 안 되나요?","JPN":"ええ、そうしたらいけませんか？","ENG":"Yes, I did. Is there a problem?","TWN":"喔，對呀，不可以嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"흐음……. 요행 같지는 않은데.","JPN":"ほう……まぐれとは思えないが。","ENG":"Hm... I don't think that was a fluke.","TWN":"嗯……感覺不是湊巧的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"내 눈으로 한 번 더 확인해 봐야겠어.","JPN":"もう一度確かめてやろう。","ENG":"I'd better check again.","TWN":"我必須再親眼確認一次！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"이거 실례했군. 백병전에도 조예가 있었나.","JPN":"これは失礼したな。白兵戦にも造詣があったのか。","ENG":"My apologies. I didn't know you were also good at hand-to-hand combat.","TWN":"失敬失敬！妳很有戰鬥天分呢！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L2_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"아직 어려 보이는데 그런 신기한 재주는 어디서 배운 거지?","JPN":"まだ幼いように見えるが、そんな不思議な技はどこで習ったんだ？","ENG":"You look pretty young. Where did you learn such an amazing trick?","TWN":"不過妳看起來這麼年輕，這身好身手是在哪學的呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 이걸 꼭 배워야 할 수 있는 건가요?","JPN":"あら？　これは習わないとできないものなのでしょうか？","ENG":"What? Isn't it something you can do without learning?","TWN":"嗯？這是需要學的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"무게 중심이 치우쳤을 때 살짝 밀어 줘서 빗나가게만 하면 돼요.","JPN":"重心が偏った時にそっと押して、外させるだけです。","ENG":"All I did was nudge your center of gravity when it was pressed toward me.","TWN":"只要在重心傾斜時，稍微推一下再側身就可以啦。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어때요, 아저씨? 듣고 나니까 참 쉽죠?","JPN":"どうですか、おじさん？　説明を聞いたら簡単でしょう？","ENG":"Say, mister. It's easy now that you know, isn't it?","TWN":"大叔OK嗎？聽起來很簡單對吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"……멋지군.","JPN":"……すばらしい。","ENG":"Impressive.","TWN":"……算妳行！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 그런 총부리와 개머리판만으로는 날 죽일 수 없다.","JPN":"だがそんな銃口と台尻だけでは俺を殺せないぞ。","ENG":"But you can't kill me with that gun barrel and butt plate.","TWN":"但是光憑那把槍是殺不死我的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"이대로 시간을 끌면 아가씨보다 그 소총이 먼저 부서질 텐데?","JPN":"時間稼ぎをすればお嬢ちゃんよりその小銃が先に壊れちまうぞ。","ENG":"I can go on fighting you, but your rifle can't.","TWN":"再這樣打下去，那支槍應該會比妳先解體吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 저도 아저씨랑 같은 생각이에요.","JPN":"はい。それは私も同感です。","ENG":"No. I completely agree with you.","TWN":"是的，我的想法和大叔一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서 준비했답니다.","JPN":"なので用意しました。","ENG":"So, I've prepared.","TWN":"所以我是有備而來的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>[코드 시그마. 알고리즘 해독 성공]</color>","JPN":"<color=#ffd34c>[コードシグマ。アルゴリズム解読成功]</color>","ENG":"<color=#ffd34c>[Code Sigma. Algorithm analysis succeeded.]</color>","TWN":"<color=#ffd34c>[CORD西格瑪。演算法判讀成功]</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L20_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>[바이러스 격리 완료]</color>","JPN":"<color=#ffd34c>[ウイルス隔離完了]</color>","ENG":"<color=#ffd34c>[Virus isolation completed.]</color>","TWN":"<color=#ffd34c>[病毒隔離完畢]</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_04"},{"id":"L21_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"……음?","JPN":"……うむ？","ENG":"Mm?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"더 이상 사람들을 해치게 두진 않을 거예요. 해적 아저씨.","JPN":"これ以上人を傷つけることはさせません、海賊のおじさん。","ENG":"I'm not going to let you hurt any more people, Mr. Pirate.","TWN":"海盜大叔，我不能再放任你傷害任何人囉。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"죽었어요!","JPN":"仕留めました！","ENG":"He's dead!","TWN":"死了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"심장에 정확히 맞았습니다!","JPN":"心臓に正確に当たりました！","ENG":"He's shot straight in the heart!","TWN":"正中心臟！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨, 어떻게 저 자와 마주하고 있는 상황에서 총을 사용하셨죠?","JPN":"お嬢様、どうやってあの状況で銃を使用できたのですか？","ENG":"Miss Jia, how did you use your gun while being so close to him?","TWN":"小姐，為什麼妳可以在那傢伙面前使用槍呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"샤오린 씨께 받은 백신 덕분이에요.","JPN":"シャオリンさんからもらったワクチンのおかげです。","ENG":"Because of Xiao Lin's antivirus.","TWN":"因為我有曉琳送我的疫苗。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"분석에 시간은 좀 걸렸지만 그래도 제때 사용할 수 있었네요.","JPN":"分析に時間はかかりましたが、間に合ってよかったです。","ENG":"It took a while to analyze the virus, but I was able to use the antivirus at the right time.","TWN":"雖然分析有花點時間，幸好有及時派上用場！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>실장님! 스캐빈저 측에서 고밀도 에너지 반응이 관측됩니다!</color>","JPN":"<color=#ffd34c>室長！　スカベンジャー側で高密度エネルギー反応が観測されました！</color>","ENG":"<color=#ffd34c>Chief! High-density energy responses are detected from the Scavengers!</color>","TWN":"<color=#ffd34c>室長！觀察到清道夫那邊有高密度能量反應！</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"적의 공격인가?","JPN":"敵の攻撃ですか？","ENG":"Is it an attack?","TWN":"是敵人的攻擊嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그건…… 아닌 것 같습니다.</color>","JPN":"<color=#ffd34c>それは……違うようです。</color>","ENG":"<color=#ffd34c>I... don't think so.</color>","TWN":"<color=#ffd34c>似乎……不是。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에너지 반응은 적의 함선이 아니라 인양 중인 저희 연구선에서 확인되고 있습니다.</color>","JPN":"<color=#ffd34c>エネルギー反応は敵の艦船ではなく、引き揚げ中の研究船で確認されています。</color>","ENG":"<color=#ffd34c>These energy responses aren't from the enemy ship but from the research ship that we're carrying.</color>","TWN":"<color=#ffd34c>能量反應的來源不是敵人的艦船，是從我們搶來的這艘研究船發出的。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"연구선에서……?","JPN":"研究船で……？","ENG":"From the research ship?","TWN":"這艘研究船……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이런!","JPN":"しまった！","ENG":"Oh, no!","TWN":"該死！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"연구선을 공격하세요! 지금 당장!","JPN":"研究船を攻撃してください！　今すぐ！","ENG":"Attack the research ship, now!","TWN":"立刻攻擊研究船！馬上！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네? 하지만 저희 임무는 연구선을 회수하는 것 아니었습니까?</color>","JPN":"<color=#ffd34c>はい？　しかし私たちの任務は研究船を回収することではありませんか？</color>","ENG":"<color=#ffd34c>Sorry? But our mission is to retrieve it.</color>","TWN":"<color=#ffd34c>可是？我們的任務不是要奪回研究船嗎？</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 임무는 잊어요! 저걸 막지 않으면 안 됩니다!","JPN":"その任務は忘れてください！　あれを止めなけばなりません！","ENG":"Forget the mission! We must stop it right now!","TWN":"忘記那個任務吧！必須阻止它！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니! 위험해요!","JPN":"ホノカさん、危ないです！","ENG":"Jin! Watch out!","TWN":"李珍姐！危險！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"크윽……?!","JPN":"くうっ……！？","ENG":"Ugh!","TWN":"呃……？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"올레. 반응 좋은데?","JPN":"オーレ、いい反応だな！","ENG":"Olé! Nice reaction!","TWN":"Ole！反應不錯喔？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"으읏…….","JPN":"うぅ……","ENG":"Ugh...","TWN":"嗚……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨! 괜찮으신가요?","JPN":"お嬢様、大丈夫ですか？","ENG":"Miss Jia! Are you okay?","TWN":"小姐！妳沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전…… 괜찮아요.","JPN":"私は……平気です。","ENG":"I'm... I'm fine.","TWN":"我……我沒事。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇지만…… 분명히 심장을 맞췄을 텐데, 어떻게 된 거죠?","JPN":"しかし……確かに心臓に当たったはずなのに、どういうことでしょう？","ENG":"But... I shot you in the heart. How are you still alive?","TWN":"怎麼會這樣……剛剛不是正中他的心臟嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"보통 사람은 거길 맞으면 그대로 끝이겠지.","JPN":"普通の人間なら当たると即死するだろうさ。","ENG":"Ordinary people die when they're shot there.","TWN":"凡人被打到心臟是會死掉沒錯。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 우리처럼 몸뚱이를 자주 손보는 경우는 달라.","JPN":"で俺たちみたいによくパーツを取り替える場合は違う。","ENG":"I'm not ordinary. I change my body parts like a girl changes her clothes.","TWN":"但像我們這種常常在保養的可就不一樣囉！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"종종 심장이 어디 붙어 있나 잊어버리기도 하거든.","JPN":"時々心臓がどこについているかも忘れちまうんだ。","ENG":"Sometimes I even forget where my heart is.","TWN":"還會常常忘記心臟的位置呢！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어이, 깡통. 작업 끝났어.","JPN":"おい、ボロ缶。作業が終わった。","ENG":"Yo, Tin Can. Our work here is done.","TWN":"喂，鐵桶！好了啦！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어서 복귀해. 늦으면 버리고 간다?","JPN":"早く復帰しろ。遅れたら捨てていくぞ？","ENG":"You'd better come back now, or we'll leave you behind.","TWN":"趕快回來，不然扔下你跑了喔？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"실장님! 괜찮으십니까?","JPN":"室長！　大丈夫ですか？","ENG":"Chief! Are you okay?","TWN":"室長！您還好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"잠깐, 저걸 봐! 뭔가가 날아온다!","JPN":"待て！あれを見ろ！　何かが飛んでくる！","ENG":"Wait, look! Something's flying in!","TWN":"等等，你們看！有東西飛過來了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"인양용 작살이다! 모두 피해!","JPN":"引き揚げ用の銛だ！　みんな避けろ！","ENG":"Salvage harpoons! Everyone, duck!","TWN":"是魚叉！大家快躲開！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"오랜만에 피가 끓는 싸움이었다.","JPN":"久しぶりに血の沸く戦いだったな。","ENG":"I haven't had such an exciting fight in a long time.","TWN":"好久沒打得這麼痛快了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK"},{"id":"L29_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"기회가 되면 다음에 다시 붙어 보자. 아가씨.","JPN":"機会があればもう一度勝負しよう、お嬢ちゃん。","ENG":"I look forward to fighting you again soon, lady.","TWN":"小姐，之後有機會再交流囉！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"저 해적 놈, 작살을 붙잡고 빠져나가다니……","JPN":"あの海賊め、銛で脱出するなんて……","ENG":"That pirate, he escaped holding onto a harpoon.","TWN":"那個海盜竟然抓著魚叉跑走了……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……예전보다 더 거칠어졌군요. 아니면 그런 자들만 살아 남았거나.","JPN":"……以前よりもさらに厄介になりましたね。それともそんな者しか生き残っていないのか。","ENG":"They've become more violent than before. Or only the most violent of them have survived.","TWN":"……好像比之前更難對付了，還是只剩那種傢伙存活下來？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>실장님! 들리십니까?</color>","JPN":"<color=#ffd34c>室長！　聞こえますか？</color>","ENG":"<color=#ffd34c>Chief! Can you hear me?</color>","TWN":"<color=#ffd34c>室長！您有聽到嗎？</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 무슨 일이죠, 함교?","JPN":"はい、どうしましたか、艦橋？","ENG":"Yes. What is it, Bridge?","TWN":"艦橋，什麼事？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>차원항로로 낙하하는 스캐빈저의 탈출 포드를 확인했습니다!</color>","JPN":"<color=#ffd34c>次元航路に落下するスカベンジャーの脱出ポッドを確認しました！</color>","ENG":"<color=#ffd34c>The Scavengers dropped an escape pod along a dimensional route!</color>","TWN":"<color=#ffd34c>已經確認到降落在次元航道的清道夫逃生艙！</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>추정 경로는 스캐빈저의 본거지인 서브스톰!</color>","JPN":"<color=#ffd34c>推定経路はスカベンジャーの本拠地であるサブストーム！</color>","ENG":"<color=#ffd34c>Its suspected destination is their base, Substorm!</color>","TWN":"<color=#ffd34c>推測路徑是清道夫的基地 次級風暴！</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>포드에서 식별되는 태그네임은……</color>","JPN":"<color=#ffd34c>ポッドから識別されるタグネームは……</color>","ENG":"<color=#ffd34c>The tag name on the pod is...</color>","TWN":"<color=#ffd34c>從艙裡辨識到的名字是……</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이볼브 원</color>?","JPN":"<color=#ffd34c>イボルブ・ワン</color>？","ENG":"<color=#ffd34c>Evolved One</color>?","TWN":"<color=#ffd34c>Evolved One</color>？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이볼브 원……?","JPN":"イボルブ・ワン……？","ENG":"Evolved One?","TWN":"Evolved One……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"왜 그러세요, 언니? 아는 이름인가요?","JPN":"どうしました、ホノカさん？　知っている名前ですか？","ENG":"What is it, Jin? Do you know this name?","TWN":"李珍姐，妳怎麼了？是妳認識的人嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……네. 아가씨. 그리고 떠올리기 싫은 이름이기도 합니다.","JPN":"……はい、お嬢様。そして思い出したくもない名前です。","ENG":"Yes, Miss Jia. And it's not a pleasant name to remember.","TWN":"是……是的，小姐，是一個我根本不願想起來的名字。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"함교! 지금 당장 진로를 서브스톰으로 수정하세요!","JPN":"艦橋！　今すぐ進路をサブストームに修正してください！","ENG":"Bridge! Change our course to Substorm right now!","TWN":"艦橋！立刻將艦船路徑修正為次級風暴！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>실장님! 서브스톰은 스캐빈저의 본거지입니다! 저희만으로는 위험할 수 있습니다!</color>","JPN":"<color=#ffd34c>室長！　サブストームはスカベンジャーの本拠地です！　私たちだけでは危険です！</color>","ENG":"<color=#ffd34c>Director, Substorm is the Scavengers' base. It's too dangerous for us to go there alone.</color>","TWN":"<color=#ffd34c>室長！次級風暴是清道夫的基地！只有我們幾個去會有危險的！</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지원 요청을 보내 두세요.","JPN":"応援要請をお願いします。","ENG":"Ask for reinforcements.","TWN":"請妳發送支援請求。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하지만 여기서 기다릴 시간은 없습니다.","JPN":"しかしここで待つ暇はありません。","ENG":"But we don't have time to wait for them.","TWN":"但我們不能在這裡空等。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이볼브 원에 코어가 탑재되기 전에…… 무슨 수를 써서라도 막아야 해요.","JPN":"イボルブ・ワンにコアが搭載される前に……何としても止めなければ。","ENG":"We must stop them before they put the core into the Evolved One.","TWN":"在核心裝載到Evolved One之前……必須不擇手段阻止這一切！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};